backend_files = [
    "d:/Claude Projects/WD Lab Project/backend/services/chatbot_service.py"
]

for filepath in backend_files:
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()

        new_content = content
        for emoji, svg in replacements.items():
            # For ⚠️, backend uses 18x18, so maybe don't replace if it's already there? No, backend has it as emoji.
            new_content = new_content.replace(emoji, svg)

        if new_content != content:
            with open(filepath, 'w', encoding='utf-8') as f:
                f.write(new_content)
            print(f"Updated {filepath}")
    except Exception as e:
        print(f"Failed {filepath}: {e}")

